                <small>@n.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationsApp.Services.Notification>? notifications;
    private CancellationTokenSource? cts;

    // Persist the initial data so it survives the prerender → interactive handoff
    // without a second fetch.
    [PersistentState]
    public List<NotificationsApp.Services.Notification>? PersistedNotifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Restore from persisted state if available; otherwise load from the service.
        PersistedNotifications ??= await NotificationService.GetInitialNotificationsAsync();
        notifications = PersistedNotifications;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender is never called during prerender, so this
            // only fires once the page is live and interactive.
            cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

                var newItems = await NotificationService.CheckForNewNotificationsAsync();
                if (newItems.Count > 0)
                {
                    notifications?.AddRange(newItems);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                // Expected on disposal — exit the loop cleanly.
                break;
            }
        }
    }

    public ValueTask DisposeAsync()
    {
        cts?.Cancel();
        cts?.Dispose();
        return ValueTask.CompletedTask;
    }
}

