namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 4;
    private readonly Lock _lock = new();

    private static readonly List<Notification> SeedNotifications =
    [
        new(1, "Welcome to the app!", new DateTime(2026, 5, 27, 8, 0, 0, DateTimeKind.Utc)),
        new(2, "Your profile was updated.", new DateTime(2026, 5, 27, 9, 30, 0, DateTimeKind.Utc)),
        new(3, "New feature: dark mode is now available.", new DateTime(2026, 5, 27, 10, 15, 0, DateTimeKind.Utc)),
    ];

    /// <summary>Returns the initial batch of notifications.</summary>
    public Task<List<Notification>> GetInitialNotificationsAsync()
    {
        return Task.FromResult(new List<Notification>(SeedNotifications));
    }

    /// <summary>Simulates polling — randomly returns 0-1 new notifications per call.</summary>
    public Task<List<Notification>> CheckForNewNotificationsAsync()
    {
        var results = new List<Notification>();

        if (Random.Shared.Next(3) == 0)
        {
            lock (_lock)
            {
                var id = _nextId++;
                results.Add(new Notification(id, $"New event #{id} arrived.", DateTime.UtcNow));
            }
        }

        return Task.FromResult(results);
    }
}

